mapper.select:
SELECT notify_type AS notifyType, COUNT(*) AS totalCount, SUM(CASE WHEN status = 1 THEN 1 ELSE 0 END) AS successCount, SUM(CASE WHEN status = 0 THEN 1 ELSE 0 END) AS failCount FROM sparkit_notify_record WHERE 1 = 1
AND create_time >= #{startTime}
AND create_time <= #{endTime}
GROUP BY notify_type ORDER BY totalCount DESC
